import jwt
from flask import Flask, request
from base64 import b32decode


def verify(password):
    """
    Verify a given password to an encoded format using the JWT encoding.

    Args:
        password (str): The password provided by the user.

    Raises:
        ValueError if the encoding is incorrect.
    Returns:
        True for correct encoding, False otherwise
    """
    try:
        token = password.split(".")[2]  # get the token from a given string.
        encoded_token = b32decode(bytes(token, "utf-8")).decode()

        return encoded_token == password

    except Exception as e:
        raise ValueError


def verify_otp(encoded_password):
    """
    Verify a given otp using JWT encoding for the encoded token.
    OTP is 6 digits.

    Args:
        encoded_password (str): The encoded password provided by user in
        an MFA format.

    Raises:
        ValueError if encoding or otp length is incorrect,
        or decoded otp is greater than 999999.
    Returns:
         True for correct encoding and otp, False otherwise
    """
    # split the encoded_password into header, payloads and signature components by splitting on '.'.
    parts = encoded_password.split(".")

    # length of parts
    # encoded password must be 3 parts. (1.24.36.907291039)
    if len(parts) == 3:
        try:
            encoded_otp = b32decode(bytes(parts[2], "utf-8")).decode()

            # otp should be only digits and less than 6 in length.
            assert all([c.isdigit() for c in encoded_otp]) and len(encoded_otp) <= 6
        except Exception as e:
            raise ValueError("Invalid otp format") from None

        return True


